//! Database access — all queries use sqlx **compile-time macros** (`query!` /
//! `query_as!` / `query_scalar!`), which type-check SQL against the schema at
//! build time. The `.sqlx/` offline cache (generated by `cargo sqlx prepare`)
//! lets Docker builds compile without a DB (`SQLX_OFFLINE=true`).

use anyhow::Result;
use sqlx::sqlite::{SqliteConnectOptions, SqliteJournalMode, SqlitePoolOptions, SqliteSynchronous};
use sqlx::{Pool, Sqlite};
use std::str::FromStr;

use crate::config;
use crate::models::{ArchiveRound, ArchiveSnapshot, Grilling, SessionStatus};

// Re-export row types — definitions live in `models`, surfaced here for callers
// that import via `crate::db::*`.
pub use crate::models::{RoundRow, RoundSummaryRow, SessionRow};

/// Create and configure the SQLite connection pool.
pub async fn create_pool() -> Result<Pool<Sqlite>> {
    let opts = SqliteConnectOptions::from_str(&format!(
        "sqlite://{}?mode=rwc",
        config::settings().db_path
    ))?
    .create_if_missing(true)
    .journal_mode(SqliteJournalMode::Wal)
    .synchronous(SqliteSynchronous::Normal)
    .busy_timeout(config::BUSY_TIMEOUT)
    .foreign_keys(true)
    .pragma("cache_size", "-200000") // 200MB page cache
    .pragma("mmap_size", "536870912") // 512MB mmap
    .pragma("wal_autocheckpoint", "1000")
    .pragma("temp_store", "MEMORY");

    let pool = SqlitePoolOptions::new()
        .max_connections(config::DB_POOL_MAX)
        .min_connections(config::DB_POOL_MIN)
        .acquire_timeout(config::ACQUIRE_TIMEOUT)
        .connect_with(opts)
        .await?;

    Ok(pool)
}

/// Run database migrations.
pub async fn run_migrations(pool: &Pool<Sqlite>) -> Result<()> {
    sqlx::migrate!("./migrations").run(pool).await?;
    Ok(())
}

// ---------------------------------------------------------------------------
// Session CRUD
// ---------------------------------------------------------------------------

/// Insert a new session with its first round. Returns the first round's id.
///
/// Order: insert the session row first (curr_round NULL), then the first round
/// (its session_id FK is now satisfied), then set curr_round to the new round
/// id. The FK `rounds.session_id → sessions.id` requires sessions to exist
/// first; curr_round → rounds.id is set after the round exists.
pub async fn create_session(
    pool: &Pool<Sqlite>,
    session_id: &str,
    grilling: &Grilling,
    created_at: i64,
    expires_at: i64,
) -> Result<i64> {
    let mut tx = pool.begin().await?;

    let grilling_json = serde_json::to_string(grilling)?;

    // Insert session (curr_round NULL initially).
    sqlx::query!(
        "INSERT INTO sessions (id, status, curr_round, name, created_at, expires_at)
         VALUES (?, 0, NULL, ?, ?, ?)",
        session_id,
        grilling.name,
        created_at,
        expires_at,
    )
    .execute(&mut *tx)
    .await?;

    // Insert first round (FK to sessions satisfied). RETURNING id is always
    // present, but sqlx types it as Option<i64> — unwrap is safe here.
    let row_id = sqlx::query_scalar!(
        "INSERT INTO rounds (session_id, seq, name, grilling, created_at)
         VALUES (?, 1, ?, ?, ?)
         RETURNING id",
        session_id,
        grilling.name,
        grilling_json,
        created_at,
    )
    .fetch_one(&mut *tx)
    .await?
    .expect("RETURNING id must be present");

    // Set the curr_round pointer to the new round.
    sqlx::query!(
        "UPDATE sessions SET curr_round = ? WHERE id = ?",
        row_id,
        session_id
    )
    .execute(&mut *tx)
    .await?;

    tx.commit().await?;
    Ok(row_id)
}

/// Get session status and metadata. Returns None if not found.
pub async fn get_session(pool: &Pool<Sqlite>, session_id: &str) -> Result<Option<SessionRow>> {
    // `id as "id!"` overrides sqlx's nullable inference for TEXT PRIMARY KEY
    // (SQLite only treats INTEGER PRIMARY KEY as implicitly NOT NULL).
    let row = sqlx::query_as!(
        SessionRow,
        r#"SELECT id as "id!", status, curr_round, name, created_at, expires_at,
                cancel_reason, cancel_detail, cancel_actor
         FROM sessions WHERE id = ?"#,
        session_id
    )
    .fetch_optional(pool)
    .await?;

    Ok(row)
}

/// Get session by ID, returning Gone if in terminal state.
///
/// DESIGN.md §319-333: GET /sessions/{id} distinguishes "never existed" (404)
/// from "existed but archived" (410). After a terminal transition the session
/// row is moved to `session_archive`, so a 410 requires falling back to the
/// archive table to recover the terminal status.
pub async fn get_session_or_gone(
    pool: &Pool<Sqlite>,
    session_id: &str,
) -> Result<SessionRow, crate::error::ApiError> {
    if let Some(row) = get_session(pool, session_id).await? {
        if row.status != 0 {
            let status = SessionStatus::try_from(row.status).unwrap_or(SessionStatus::Expired);
            return Err(crate::error::ApiError::Gone {
                detail: status.terminal_detail().to_string(),
            });
        }
        return Ok(row);
    }

    // Fall back to archive.
    if let Some((status_int, _reason)) = get_archive_status(pool, session_id).await? {
        let status = SessionStatus::try_from(status_int).unwrap_or(SessionStatus::Expired);
        return Err(crate::error::ApiError::Gone {
            detail: status.terminal_detail().to_string(),
        });
    }

    Err(crate::error::ApiError::NotFound)
}

/// Update session status (completed or cancelled). Returns rows affected.
pub async fn update_session_status(
    pool: &Pool<Sqlite>,
    session_id: &str,
    status: i64,
    cancel_reason: Option<&str>,
    cancel_detail: Option<&str>,
    cancel_actor: Option<&str>,
) -> Result<u64> {
    let result = sqlx::query!(
        "UPDATE sessions SET status = ?, cancel_reason = ?, cancel_detail = ?, cancel_actor = ?
         WHERE id = ? AND status = 0",
        status,
        cancel_reason,
        cancel_detail,
        cancel_actor,
        session_id,
    )
    .execute(pool)
    .await?;

    Ok(result.rows_affected())
}

// ---------------------------------------------------------------------------
// Round CRUD
// ---------------------------------------------------------------------------

/// Create a new round. Returns (seq, id).
pub async fn create_round(
    pool: &Pool<Sqlite>,
    session_id: &str,
    grilling: &Grilling,
    created_at: i64,
) -> Result<(i64, i64)> {
    let mut tx = pool.begin().await?;

    let max_seq: Option<i64> = sqlx::query_scalar!(
        "SELECT MAX(seq) FROM rounds WHERE session_id = ?",
        session_id
    )
    .fetch_one(&mut *tx)
    .await?;

    let new_seq = max_seq.unwrap_or(0) + 1;
    let grilling_json = serde_json::to_string(grilling)?;

    let round_id = sqlx::query_scalar!(
        "INSERT INTO rounds (session_id, seq, name, grilling, created_at)
         VALUES (?, ?, ?, ?, ?)
         RETURNING id",
        session_id,
        new_seq,
        grilling.name,
        grilling_json,
        created_at,
    )
    .fetch_one(&mut *tx)
    .await?
    .expect("RETURNING id must be present");

    sqlx::query!(
        "UPDATE sessions SET curr_round = ? WHERE id = ?",
        round_id,
        session_id
    )
    .execute(&mut *tx)
    .await?;

    tx.commit().await?;
    Ok((new_seq, round_id))
}

/// Get the current round for a session.
pub async fn get_current_round(pool: &Pool<Sqlite>, session_id: &str) -> Result<Option<RoundRow>> {
    let row = sqlx::query_as!(
        RoundRow,
        "SELECT r.id, r.session_id, r.seq, r.name, r.grilling, r.response, r.created_at
         FROM rounds r
         JOIN sessions s ON s.curr_round = r.id
         WHERE s.id = ?",
        session_id
    )
    .fetch_optional(pool)
    .await?;

    Ok(row)
}

/// Get a round by session_id and seq.
pub async fn get_round(
    pool: &Pool<Sqlite>,
    session_id: &str,
    seq: i64,
) -> Result<Option<RoundRow>> {
    let row = sqlx::query_as!(
        RoundRow,
        "SELECT id, session_id, seq, name, grilling, response, created_at
         FROM rounds WHERE session_id = ? AND seq = ?",
        session_id,
        seq,
    )
    .fetch_optional(pool)
    .await?;

    Ok(row)
}

/// List all rounds for a session (summary).
pub async fn list_rounds(pool: &Pool<Sqlite>, session_id: &str) -> Result<Vec<RoundSummaryRow>> {
    let rows = sqlx::query_as!(
        RoundSummaryRow,
        "SELECT seq, name, response IS NOT NULL AS has_response
         FROM rounds WHERE session_id = ? ORDER BY seq",
        session_id
    )
    .fetch_all(pool)
    .await?;

    Ok(rows)
}

/// Get a round by its physical ID (curr_round lookup).
pub async fn get_round_by_id(pool: &Pool<Sqlite>, round_id: i64) -> Result<Option<RoundRow>> {
    let row = sqlx::query_as!(
        RoundRow,
        "SELECT id, session_id, seq, name, grilling, response, created_at
         FROM rounds WHERE id = ?",
        round_id
    )
    .fetch_optional(pool)
    .await?;

    Ok(row)
}

/// Check if a round exists.
pub async fn round_exists(pool: &Pool<Sqlite>, session_id: &str, seq: i64) -> Result<bool> {
    let exists: i64 = sqlx::query_scalar!(
        "SELECT EXISTS(SELECT 1 FROM rounds WHERE session_id = ? AND seq = ?)",
        session_id,
        seq
    )
    .fetch_one(pool)
    .await?;
    Ok(exists != 0)
}

// ---------------------------------------------------------------------------
// Response CRUD
// ---------------------------------------------------------------------------

/// Submit a response. Returns Ok(true) if first submission, Ok(false) if
/// already submitted (concurrent conflict).
pub async fn submit_response(
    pool: &Pool<Sqlite>,
    session_id: &str,
    seq: i64,
    response_json: &str,
) -> Result<bool> {
    let result = sqlx::query!(
        "UPDATE rounds SET response = ? WHERE session_id = ? AND seq = ? AND response IS NULL",
        response_json,
        session_id,
        seq,
    )
    .execute(pool)
    .await?;
    Ok(result.rows_affected() == 1)
}

/// Get the response for a round. Ok(None) if no response yet or round absent.
pub async fn get_response(
    pool: &Pool<Sqlite>,
    session_id: &str,
    seq: i64,
) -> Result<Option<String>> {
    let row = sqlx::query_scalar!(
        "SELECT response FROM rounds WHERE session_id = ? AND seq = ?",
        session_id,
        seq
    )
    .fetch_optional(pool)
    .await?;
    // response is nullable: fetch_optional returns Option<Option<String>>;
    // outer None = no row, inner None = NULL. Flatten.
    Ok(row.flatten())
}

// ---------------------------------------------------------------------------
// Archive
// ---------------------------------------------------------------------------

/// Archive a session and all its rounds. Returns Ok(true) if archived,
/// Ok(false) if already gone (no-op).
pub async fn archive_session(
    pool: &Pool<Sqlite>,
    session_id: &str,
    status: i64,
    now: i64,
) -> Result<bool> {
    let mut tx = pool.begin().await?;

    let session = sqlx::query_as!(
        SessionRow,
        r#"SELECT id as "id!", status, curr_round, name, created_at, expires_at,
                cancel_reason, cancel_detail, cancel_actor
         FROM sessions WHERE id = ?"#,
        session_id
    )
    .fetch_optional(&mut *tx)
    .await?;

    let session = match session {
        Some(s) => s,
        None => {
            tx.commit().await?;
            return Ok(false);
        }
    };

    let rounds = sqlx::query_as!(
        RoundRow,
        "SELECT id, session_id, seq, name, grilling, response, created_at
         FROM rounds WHERE session_id = ? ORDER BY seq",
        session_id
    )
    .fetch_all(&mut *tx)
    .await?;

    let total_rounds = rounds.len() as i64;
    let snapshot = ArchiveSnapshot {
        rounds: rounds
            .iter()
            .map(|r| ArchiveRound {
                seq: r.seq,
                name: r.name.clone(),
                grilling: r.grilling.clone(),
                response: r.response.clone(),
                created_at: r.created_at,
            })
            .collect(),
    };
    let snapshot_json = serde_json::to_string(&snapshot)?;

    sqlx::query!(
        "INSERT INTO session_archive
         (id, status, name, cancel_reason, cancel_detail, cancel_actor, total_rounds, created_at, archived_at, snapshot)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
        session_id,
        status,
        session.name,
        session.cancel_reason,
        session.cancel_detail,
        session.cancel_actor,
        total_rounds,
        session.created_at,
        now,
        snapshot_json,
    )
    .execute(&mut *tx)
    .await?;

    sqlx::query!("DELETE FROM sessions WHERE id = ?", session_id)
        .execute(&mut *tx)
        .await?;

    tx.commit().await?;
    Ok(true)
}

/// Find expired sessions (status=0 and expires_at < now).
pub async fn find_expired_sessions(pool: &Pool<Sqlite>, now: i64) -> Result<Vec<String>> {
    let rows = sqlx::query!(
        "SELECT id FROM sessions WHERE status = 0 AND expires_at < ?",
        now
    )
    .fetch_all(pool)
    .await?;
    Ok(rows.into_iter().filter_map(|r| r.id).collect())
}

/// Find all active sessions for crash recovery.
pub async fn find_active_sessions(pool: &Pool<Sqlite>, now: i64) -> Result<Vec<String>> {
    let rows = sqlx::query!(
        "SELECT id FROM sessions WHERE status = 0 AND expires_at > ?",
        now
    )
    .fetch_all(pool)
    .await?;
    Ok(rows.into_iter().filter_map(|r| r.id).collect())
}

/// Look up a session's terminal status (+ cancel_reason) in the archive.
pub async fn get_archive_status(
    pool: &Pool<Sqlite>,
    session_id: &str,
) -> Result<Option<(i64, Option<String>)>> {
    let row = sqlx::query!(
        "SELECT status, cancel_reason FROM session_archive WHERE id = ?",
        session_id
    )
    .fetch_optional(pool)
    .await?;
    Ok(row.map(|r| (r.status, r.cancel_reason)))
}
